import{_ as o,c as r,o as s,ag as t}from"./chunks/framework.Dj4VfQLU.js";const g=JSON.parse('{"title":"How to report issues","description":"","frontmatter":{"icon":"headset"},"headers":[],"relativePath":"how-to-report-issues.md","filePath":"how-to-report-issues.md"}'),i={name:"how-to-report-issues.md"};function n(a,e,l,p,u,d){return s(),r("div",null,e[0]||(e[0]=[t('<h1 id="how-to-report-issues" tabindex="-1">How to report issues <a class="header-anchor" href="#how-to-report-issues" aria-label="Permalink to &quot;How to report issues&quot;">​</a></h1><p>We welcome and review bug reports to improve the stability and quality of BetterTaxi and other BetterSuite products. However, the scope of support and response depends on your license status and support plan.</p><hr><h4 id="📬-reporting-bugs-for-everyone" tabindex="-1">📬 Reporting Bugs (For Everyone) <a class="header-anchor" href="#📬-reporting-bugs-for-everyone" aria-label="Permalink to &quot;📬 Reporting Bugs (For Everyone)&quot;">​</a></h4><p>Even if you haven&#39;t purchased a license or your support period has expired, you are <strong>still welcome to report bugs</strong> — especially if discovered through the official live demo.</p><p><strong>📧 Email for Bug Reports:</strong></p><p>Send to: <a href="mailto:contact@lumeagency.io" target="_blank" rel="noreferrer"><strong>contact@lumeagency.io</strong></a></p><blockquote><p>⚠️ <strong>Important:</strong> We only consider bugs reproduced in the <strong>unmodified live demo or official installation</strong>.<br> Bugs found in <strong>customized builds</strong> will not be reviewed.</p></blockquote><p><strong>📝 Recommended Bug Report Format:</strong></p><p>Please include the following to help us review efficiently:</p><ul><li><strong>Target App</strong> (e.g., Driver App, Admin Panel)</li><li><strong>Platform</strong> (e.g., Android, iOS, Web)</li><li><strong>Version</strong> (e.g., v3.2.1)</li><li><strong>Steps to Reproduce</strong> (as clearly as possible)</li><li><strong>Screenshots or Video</strong> (if applicable)</li><li><strong>Expected vs Actual Behavior</strong></li></ul><blockquote><p>Bug reports do <strong>not guarantee a personal response</strong>, but they are always reviewed by our product team.</p></blockquote><hr><h4 id="🎟️-support-requests-for-licensed-users" tabindex="-1">🎟️ Support Requests (For Licensed Users) <a class="header-anchor" href="#🎟️-support-requests-for-licensed-users" aria-label="Permalink to &quot;🎟️ Support Requests (For Licensed Users)&quot;">​</a></h4><p>If you have a <strong>valid support license</strong>, you may submit tickets for technical assistance through our support portal. This is the preferred method for installation help and operational issues.</p><p><strong>🔐 What to Include:</strong></p><ul><li>Your <strong>purchase code</strong> (for validation)</li><li>A <strong>clear description</strong> of the issue</li><li><strong>Server access credentials</strong> (SSH or panel-based access) <ul><li>You may reset your password after resolution</li></ul></li><li>Relevant <strong>screenshots or logs</strong></li></ul><p><strong>🚫 Limitations:</strong></p><ul><li>We <strong>do not</strong> offer support for customized or self-modified builds</li><li>We only support issues involving the installation and operation of the <strong>unmodified product</strong></li></ul><p><strong>⏱️ Response Time:</strong></p><ul><li>Our team aims to respond to support tickets within <strong>2 working days</strong></li></ul><hr><h4 id="🥇-pro-plus-plan-users" tabindex="-1">🥇 Pro Plus Plan Users <a class="header-anchor" href="#🥇-pro-plus-plan-users" aria-label="Permalink to &quot;🥇 Pro Plus Plan Users&quot;">​</a></h4><p>If you&#39;re on a <strong>Pro Plus plan</strong>, you receive:</p><ul><li><strong>Priority support</strong></li><li><strong>Direct messaging access</strong> to our developers via private channels</li><li><strong>Conflict resolution and migration help</strong> during version upgrades</li></ul><hr><h4 id="🔐-privacy-security" tabindex="-1">🔐 Privacy &amp; Security <a class="header-anchor" href="#🔐-privacy-security" aria-label="Permalink to &quot;🔐 Privacy &amp; Security&quot;">​</a></h4><ul><li>Do <strong>not</strong> include database dumps or passwords in email bug reports</li><li>Use secure support channels for credentials if needed</li><li>We treat all credentials confidentially and recommend changing them after resolution</li></ul>',28)]))}const h=o(i,[["render",n]]);export{g as __pageData,h as default};
